import{_ as t,C as r,o as s,c as e,af as o,E as n,j as i,a as p}from"./chunks/framework.DuHE0XFB.js";const k=JSON.parse('{"title":"成都 - 马尔康 - 色达 - 稻城亚丁","description":"","frontmatter":{"title":"成都 - 马尔康 - 色达 - 稻城亚丁","date":"2023-08-21T02:01:23.000Z"},"headers":[],"relativePath":"posts/sichuan.md","filePath":"posts/sichuan.md","lastUpdated":1783570921000}'),u={name:"posts/sichuan.md"};function d(m,l,f,b,P,x){const a=r("ImageGallery");return s(),e("div",null,[l[0]||(l[0]=o("",11)),n(a,{dir:"/images/sichuan/"}),l[1]||(l[1]=i("h3",{id:"马尔康",tabindex:"-1"},[p("马尔康 "),i("a",{class:"header-anchor",href:"#马尔康","aria-label":'Permalink to "马尔康"'},"​")],-1)),l[2]||(l[2]=i("p",null,"阿坝藏族羌族自治州首府，离成都 300 多公里，全程有高速，马尔康市是嘉绒藏区的核心地区，也是历史上最后的土司衰亡的地方，当年红军在这里留下了很多故事。",-1)),l[3]||(l[3]=i("p",null,"行：成都茶店子客运站坐 8:30 的车到马尔康客运站，全程高速，大概 4.5 小时，中途司机会在休息区停车让大家上厕所，厕所边上买到了便宜又好吃的大西梅",-1)),l[4]||(l[4]=i("p",null,"住：选择住在市里，吃饭什么的比较方便，要想住藏式民居可以选择住西索民居",-1)),l[5]||(l[5]=i("p",null,"吃：牛家店牦牛肉野生菌汤锅！！！，要了个套餐，太好吃了，菌子很鲜，肉也多，店家泡的酒也不错，喝一口脸就红了",-1)),l[6]||(l[6]=i("p",null,"玩：西索民居、卓克基吐司官寨，这两个地方挨着，地方不大，一两个小时就能逛完，这次比较意外的是吐司官寨因装修关门，在山上装修小哥的引导下溜进去了，结果却被里面看似友军的工作人员赶了出来，惊喜的是去了计划外的更达寺，太阳在下山前将最后一抹光洒在寺内的金色佛塔和金色墙壁上 blingbling 的，走进寺内一层大殿，这里供奉的是莲花生大师，他是第一位将佛法带到西藏的人，所以在藏人心中有极高的地位，在寺院工作人员允许下拍了一张照片，二层大殿供奉的是四臂观音，他和千手千眼观音同样是观世音菩萨的化身之一，三层大殿供奉的是绿度母，据说观音菩萨在无量劫前，已普救了无数众生，可是有一天，菩萨用她的慧眼观察六道，发现受苦的众生并未减少，顿生忧悲，双眼流出眼泪，眼泪变成了莲花，莲花又变成了绿度母，所以绿度母是最慈悲的，供奉她能解脱八种苦难，于是又称绿度母为救八难度母。",-1)),n(a,{dir:"/images/sichuan/"}),l[7]||(l[7]=i("h3",{id:"色达",tabindex:"-1"},[p("色达 "),i("a",{class:"header-anchor",href:"#色达","aria-label":'Permalink to "色达"'},"​")],-1)),l[8]||(l[8]=i("p",null,"色达县城附近 20 公里有一条山沟叫喇荣沟，世界最大的佛学院喇荣五明佛学院就在这里，在山顶的观景台可以观赏到数万红色僧房密布山坡的景观，到了晚上开灯后，更是好看。因为佛学院是学校不是景点，所以要提前预约才能乘车进入，约的不是门票，而是进入佛学院大巴车的往返汽车票。",-1)),l[9]||(l[9]=i("p",null,"“喇荣沟进沟预约”小程序在每天的 18:00 可以约 3 天后 10:00 或 15:30 从“色达洛若集散中心”开往“喇荣沟”的汽车票，即使是旺季只要准时打开小程序，并在一分钟内完成填写个人信息并完成支付操作一般都能约上，万一抢不到票，可以在一小时内或第二天早些时候看下是否有人退票，还不行的话可以到色达县城后在金马广场对面的色达旅游文化局现场约第二天的车票，车次时间会和线上看到的不同，目前还有项规定，15 天内只能预约进入佛学院一次。",-1)),l[10]||(l[10]=i("p",null,"行：马尔康到色达县路程近 300 公里，开车需要大概 4.5 小时，没有高速，山路多，也没有班车，只能选择拼车或包车前往，包车价格一千，建议选择正规出租车，在市内打车时和师傅聊就行，早出门可以避开很多大车",-1)),l[11]||(l[11]=i("p",null,"住：佛学院里的喇荣宾馆只能到现场办住宿，价格相对不贵，淡季可以选择住这里，旺季可以提前订色达县城的酒店，县城随时可能会停电停水，但并不是所有酒店都会停，可以选择当天能免费退房的酒店，要是停电了不想等可以更换酒店",-1)),l[12]||(l[12]=i("p",null,"吃：在佛学院赶上饭点儿可以去“喇荣饭店“吃饭，在县城选择比较多，藏餐、汤锅、炒菜什么都有",-1)),l[13]||(l[13]=i("p",null,"玩：县城到色达洛若集散中心大概 20 公里，可以包出租车，也可以在金马广场对面乘大巴车，到集散中心后凭身份证乘坐大巴车进入喇荣沟，也就是佛学院，司机会要求大家在一小时内上车返回，建议高反不严重的情况下一定要在佛学院看完夜景再自行下山，佛学院的夜景太漂亮了，不知道这世界上是不是还有这样的地方，晚上赶不上未班九点的公交也没关系，走路大概一小时可以下山，沿途可以近距离看看喇嘛和觉姆住的红房子，还可以去转经，下山后联系出租司机回县城酒店",-1)),l[14]||(l[14]=i("p",null,"PS：第二天睡觉前高反头疼，晚上睡的不好，回想白天在东嘎寺内上完厕所后看到寺庙宿舍区有喇嘛在打篮球，搭讪想一起打，结果以不让进入为由被拒，感谢！",-1)),n(a,{dir:"/images/sichuan/"}),l[15]||(l[15]=i("h3",{id:"稻城县香格里拉镇",tabindex:"-1"},[p("稻城县香格里拉镇 "),i("a",{class:"header-anchor",href:"#稻城县香格里拉镇","aria-label":'Permalink to "稻城县香格里拉镇"'},"​")],-1)),l[16]||(l[16]=i("p",null,"位于甘孜藏族自治州，稻城亚丁景区是这里最著名的景点，景区门票可连续进入景区两次，第二次进入时需要补 60 元的往返大巴车票，景区里面坐落着由仙乃日、央迈勇、夏诺多吉三座雪峰组成的三神山，分别代表观音菩萨、文殊菩萨、金刚手菩萨，还有牛奶海、五色海和珍珠海，其中五色海是神湖，传说能“返演历史，预测未来”。",-1)),l[17]||(l[17]=i("p",null,"行：色达到稻城县 500 多公里，全是山路，大概需要 10.5 小时，包车两千四，稻城县到香格里拉镇大概 1.5 小时，包车两百，从香格里拉镇到稻城机场大概 2 小时，包车四百",-1)),l[18]||(l[18]=i("p",null,"住：香格里拉镇海拔 2900 多米，住在这里不会有高反，离景区也近，如果对自己有信心不会高反，也可以住在景区内的亚丁村",-1)),l[19]||(l[19]=i("p",null,"吃：小镇上吃饭地方很多，七八月正是菌子下来的时候，可以吃新鲜的菌汤牛肉锅，这里有很多网红店，味道区别不大，去景区时需要带上中午吃的面包和水，水不用带太多，路上有补给站，厕所也充足，中午想吃热的可以带自嗨锅，不建议带方便面，景区补给站的热水是泡不开的",-1)),l[20]||(l[20]=i("p",null,"玩：夏天去需要带雨衣，随时都可能下雨，雨停后不要脱掉就扔，随时会再下，景区游玩分长线短线，通常大家都是分两天游玩，也有体力极好者可以一天走完，走长线尽量七点就吃好早饭出发，路程较远留足时间，凭身份证进入景区后需要乘坐大概四十分钟的大巴车到下一站，进景区时要坐左边，可以观景，晕车的话记得吃晕车药，山路都是急弯，司机开车也快，需提前备好塑料袋，下了大巴车后步行几百米，需要购票乘电瓶车再走大概六七公里，这段路不要考虑步行，体力极好者除外，下了电瓶车后，下一站就是长线的终点，海拔 4600 米的牛奶海和海拔 4700 米的五色海了，体力极差的可以选择骑马继续代步一段，为了马的安全，180 斤以上的不让骑，大部分人都会选择自己徒步去牛奶海和五色海，沿途算上拍照和吃饭休息的时间，赶 18:00 出景区的电瓶车还是来的及的。第二天游玩短线时会轻松很多，进景区前提前补 60 元的大巴车票，然后同样坐在左排乘车，下车后不需要往电瓶车站方向走，路边就能够看到冲古寺，沿小路过去就行，可以在寺内逗留参观，听僧人念平安经，还可以随着当地人转寺以洗清自己的罪孽，离冲古寺不远就是珍珠海，也叫卓玛拉措，在这里可以吃饭，闲坐，看猴子跳水，还可以转湖一周再洗洗自己的罪孽。",-1)),n(a,{dir:"/images/sichuan/"})])}const T=t(u,[["render",d]]);export{k as __pageData,T as default};
